import{_ as a,o as e,c as n,ae as i}from"./chunks/framework.C7qU-Vik.js";const k=JSON.parse('{"title":"monad.ai","description":"","frontmatter":{},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),t={name:"index.md"};function o(l,s,p,h,r,c){return e(),n("div",null,[...s[0]||(s[0]=[i(`<h1 id="monad-ai" tabindex="-1">monad.ai <a class="header-anchor" href="#monad-ai" aria-label="Permalink to &quot;monad.ai&quot;">​</a></h1><h6 id="subtractive-synthesis" tabindex="-1">Subtractive Synthesis <a class="header-anchor" href="#subtractive-synthesis" aria-label="Permalink to &quot;Subtractive Synthesis&quot;">​</a></h6><p><strong>Current status:</strong> monad.ai v2.1.1 includes the mesh-aware NRP work through Phase 6: namespace discovery, selector-aware routing, production scoring, decision introspection, decision logs, continuous reward, and low-margin exploration.</p><p>Start here for the current NRP implementation:</p><ul><li><p><a href="./NRP/status">NRP Implementation Status</a></p></li><li><p><a href="./NRP/scoring">NRP Scoring Engine</a></p></li><li><p><a href="./NRP/testing">NRP Test Documentation</a></p></li><li><p><a href="./api/README">Generated API Reference</a></p></li><li><p>Resolves namespace paths from the <code>Host</code> header of incoming HTTP requests</p></li><li><p>Accepts writes as semantic memory events, appended to a hash-chained log</p></li><li><p>Serves reads as path resolutions over the kernel tree</p></li><li><p>Handles claim/open lifecycle for anchoring identities to namespaces The storage is the kernel. There is no database, no parallel ledger, no second truth.</p></li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GET /profile/name</span></span>
<span class="line"><span>Host: jabellae.cleaker.me</span></span>
<span class="line"><span>→ resolves profile.name within the jabellae.cleaker.me namespace</span></span>
<span class="line"><span></span></span>
<span class="line"><span>POST /</span></span>
<span class="line"><span>Host: jabellae.cleaker.me</span></span>
<span class="line"><span>{ &quot;expression&quot;: &quot;profile.name&quot;, &quot;value&quot;: &quot;José&quot; }</span></span>
<span class="line"><span>→ writes profile.name into the namespace memory log</span></span></code></pre></div><hr><h2 id="how-namespace-resolution-works" tabindex="-1">How namespace resolution works <a class="header-anchor" href="#how-namespace-resolution-works" aria-label="Permalink to &quot;How namespace resolution works&quot;">​</a></h2><p>The <code>Host</code> header of each request determines the namespace. The <strong>monad.ai</strong> does not need to be told which namespace it &quot;is&quot; — every request carries its own namespace context.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Host: cleaker.me → namespace: cleaker.me</span></span>
<span class="line"><span>Host: jabellae.cleaker.me → namespace: jabellae.cleaker.me</span></span>
<span class="line"><span>Host: mexicoencuesta.com → namespace: mexicoencuesta.com</span></span></code></pre></div><p>This means a <strong>monad.ai</strong> can serve multiple namespaces, and any namespace is accessible as long as the <code>Host</code> header matches.</p><p><strong>Netget</strong> routes the real domain to the <strong>monad</strong> port:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://cleaker.me  →  reverse proxy  →  localhost:8161</span></span></code></pre></div><p>In local development, the daemon is accessible directly via hostname:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>http://suis-macbook-air.local:8161/</span></span></code></pre></div><hr><h2 id="the-kernel-is-the-storage" tabindex="-1">The kernel is the storage <a class="header-anchor" href="#the-kernel-is-the-storage" aria-label="Permalink to &quot;The kernel is the storage&quot;">​</a></h2><p><code>monad.ai</code> runs a <a href="https://github.com/neurons-me/.me" target="_blank" rel="noreferrer"><code>.me</code></a> kernel backed by a <code>DiskStore</code>. Every write becomes a memory event in an append-only, hash-chained log:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>memoryHash → prevMemoryHash → path → operator → value → timestamp → namespace</span></span></code></pre></div><p>The <code>/blocks</code> endpoint is a projection of that memory log — not a separate ledger. When the daemon restarts, it hydrates from the DiskStore. No data is lost. No migrations needed.</p><hr><h2 id="identity-and-claims" tabindex="-1">Identity and claims <a class="header-anchor" href="#identity-and-claims" aria-label="Permalink to &quot;Identity and claims&quot;">​</a></h2><p>Before a namespace can receive writes, it must be claimed. A claim anchors a cryptographic identity — derived from a seed via <a href="https://github.com/neurons-me/.me" target="_blank" rel="noreferrer"><code>.me</code></a> — to a namespace:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>POST /</span></span>
<span class="line"><span>Host: jabellae.cleaker.me</span></span>
<span class="line"><span>{ &quot;operation&quot;: &quot;claim&quot;, &quot;secret&quot;: &quot;...&quot;, &quot;proof&quot;: { ... } }</span></span></code></pre></div><p>Opening a claimed namespace returns the memory log for that identity, which the caller can replay locally into their own <code>.me</code> kernel:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>POST /</span></span>
<span class="line"><span>Host: jabellae.cleaker.me</span></span>
<span class="line"><span>{ &quot;operation&quot;: &quot;open&quot;, &quot;secret&quot;: &quot;...&quot;, &quot;identityHash&quot;: &quot;...&quot; }</span></span>
<span class="line"><span>→ returns memories replayable by .me</span></span></code></pre></div><p>The claim is anchored to an <code>identityHash</code> produced by <code>.me</code>. The daemon verifies the proof but does not hold the seed. The seed never leaves the client.</p><hr><h2 id="the-stack" tabindex="-1">The stack <a class="header-anchor" href="#the-stack" aria-label="Permalink to &quot;The stack&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.me        →  the semantic kernel. derives identity, holds the tree, produces proofs.</span></span>
<span class="line"><span>monad.ai   →  the daemon. runs the kernel, exposes it over HTTP, resolves namespaces.</span></span>
<span class="line"><span>cleaker    →  the binder. takes a .me instance and projects it into a namespace context.</span></span></code></pre></div><p>The current mesh layer adds:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>monad index      → fast structural discovery: who could answer?</span></span>
<span class="line"><span>mesh selector    → execution constraint: which candidates qualify?</span></span>
<span class="line"><span>scoring engine   → adaptive decision: who should answer?</span></span>
<span class="line"><span>decision log     → correlated outcome: did that choice work?</span></span></code></pre></div><p><code>monad.ai</code> is one possible surface. You can run your own daemon on any hostname or domain. The namespace is not tied to this implementation.</p><hr><h2 id="running-locally" tabindex="-1">Running locally <a class="header-anchor" href="#running-locally" aria-label="Permalink to &quot;Running locally&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> npm</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SEED</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;your-seed&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> node</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dist/server.js</span></span></code></pre></div><p>The daemon listens on port <code>8161</code> by default. Set <code>PORT</code> to change it.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># read from the root namespace</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:8161/profile/name</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># write to a namespace</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -X</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> POST</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:8161/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Host: jabellae.localhost&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Content-Type: application/json&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;{&quot;expression&quot;:&quot;profile.name&quot;,&quot;value&quot;:&quot;José&quot;}&#39;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># read it back</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Host: jabellae.localhost&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:8161/profile/name</span></span></code></pre></div><hr><h2 id="protocol" tabindex="-1">Protocol <a class="header-anchor" href="#protocol" aria-label="Permalink to &quot;Protocol&quot;">​</a></h2><p><code>monad.ai</code> implements the HTTP binding described in <a href="./Namespace-Protocol-Resolution">Namespace Resolution Protocol v0.2.1</a>.</p><p>The canonical resource grammar is:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>me://namespace[selector]:operation/path</span></span></code></pre></div><p>The current HTTP binding maps this to:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GET  /&lt;path&gt;   Host: &lt;namespace&gt;   →  read</span></span>
<span class="line"><span>POST /         Host: &lt;namespace&gt;   →  write | claim | open</span></span>
<span class="line"><span>GET  /resolve?target=me://namespace:read/path → bridge through the mesh</span></span></code></pre></div><p>Mesh discovery endpoints:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:8161/.mesh/monads</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;http://localhost:8161/.mesh/resolve?namespace=suis-macbook-air.local&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;http://localhost:8161/.mesh/resolve?monad=frank&quot;</span></span></code></pre></div><p>Decision observability:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">MONAD_DECISION_LOG</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">~/.monad/decisions.jsonl</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tsx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/analyze-decisions.ts</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.monad/decisions.jsonl</span></span></code></pre></div><hr><h2 id="what-it-is-not" tabindex="-1">What it is not <a class="header-anchor" href="#what-it-is-not" aria-label="Permalink to &quot;What it is not&quot;">​</a></h2><ul><li>Not a central registry. There is no global list of namespaces.</li><li>Not an identity provider. Identity is derived by <code>.me</code> from the user&#39;s seed.</li><li>Not a replacement for a database. It is a semantic surface for live state and identity.</li><li>Not the only possible daemon. Anyone can run a compatible surface on any domain.</li></ul><hr><h2 id="license" tabindex="-1">License <a class="header-anchor" href="#license" aria-label="Permalink to &quot;License&quot;">​</a></h2><p><strong>MIT</strong> — <a href="https://neurons.me/" target="_blank" rel="noreferrer">neurons.me</a></p>`,55)])])}const u=a(t,[["render",o]]);export{k as __pageData,u as default};
